Here's a Python program that reads all the text files under a directory, processes the text data, and returns the top-5 words with the most number of occurrences:

```python
import os
import nltk
from collections import Counter

def count_words(file_path):
    file_content = []
    with open(file_path, 'r', encoding='utf-8') as f:
        for line in f:
            file_content.extend(line.strip().split())
    return Counter(file_content)

def process_directory(directory_path):
    word_counts = {}
    for root, dirs, files in os.walk(directory_path):
        for file in files:
            if file.endswith('.txt'):
                file_path = os.path.join(root, file)
                file_words = count_words(file_path)
                for word, count in file_words.items():
                    if word in word_counts:
                        word_counts[word] += count
                    else:
                        word_counts[word] = count
    return word_counts

def top_5_words(word_counts):
    sorted_counts = sorted(word_counts.items(), key=lambda x: x[1], reverse=True)
    return [item[0] for item in sorted_counts[:5]]

def main():
    directory_path = 'path/to/your/text/files'  # Replace with the actual directory path
    word_counts = process_directory(directory_path)
    top_5_words = top_5_words(word_counts)
    print(f'Top 5 words: {top_5_words}')

if __name__ == '__main__':
    main()
```

Replace `'path/to/your/text/files'` with the actual path to the directory containing your text files. The program reads all the .txt files under the specified directory, processes the text data, and returns the top-5 words with the most number of occurrences. The words are sorted in descending order based on their occurrence count.

